+fn base_inode_for_checksum(inode_size: usize, extra_isize: u16) -> Vec<u8> {
+    let mut inode = vec![0_u8; inode_size];
+    inode[0x00..0x02].copy_from_slice(&(ffs_types::S_IFREG | 0o644).to_le_bytes());
